Below is a simple HTML file that includes JavaScript and CSS to visualize binary search on a sorted array. This example creates a sorted array of numbers from 1 to 20, but you can easily modify the array and the target input field to test different scenarios.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Binary Search Visualization</title>
<style>
  .box {
    display: inline-block;
    width: 20px;
    height: 20px;
    border: 1px solid black;
    margin: 2px;
    text-align: center;
    line-height: 20px;
  }
  .highlight {
    background-color: yellow;
  }
  .searchRange {
    background-color: lightblue;
  }
  .result {
    font-size: 24px;
    margin-top: 20px;
  }
</style>
</head>
<body>

<input id="target" type="number" placeholder="Target number">
<button id="step">Step</button>
<div id="arrayDisplay"></div>
<div id="result" class="result"></div>

<script>
  let array = Array.from({length: 20}, (_, i) => i + 1); // Sorted array from 1 to 20
  let target = 0;
  let left = 0;
  let right = array.length - 1;
  let found = false;
  let stepCount = 0;

  const arrayDisplay = document.getElementById('arrayDisplay');
  const targetInput = document.getElementById('target');
  const stepButton = document.getElementById('step');
  const resultDiv = document.getElementById('result');

  function renderArray() {
    arrayDisplay.innerHTML = '';
    for (let i = 0; i < array.length; i++) {
      let box = document.createElement('div');
      box.className = 'box';
      if (i >= left && i <= right) {
        box.classList.add('searchRange');
      }
      if (i === Math.floor((left + right) / 2)) {
        box.classList.add('highlight');
      }
      box.textContent = array[i];
      arrayDisplay.appendChild(box);
    }
  }

  stepButton.addEventListener('click', () => {
    target = parseInt(targetInput.value);
    if (isNaN(target)) return;

    if (stepCount === 0) {
      left = 0;
      right = array.length - 1;
      found = false;
    }

    if (left <= right) {
      let mid = Math.floor((left + right) / 2);
      stepCount++;

      if (array[mid] === target) {
        found = true;
        resultDiv.textContent = `Found ${target} at step ${stepCount}!`;
      } else if (array[mid] < target) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    } else {
      resultDiv.textContent = `Not found in ${stepCount} steps.`;
    }

    renderArray();
  });

  // Initial render
  renderArray();
</script>

</body>
</html>
```

