<body>

<textarea id="csvData" rows="10" cols="50" placeholder="Paste CSV data here..."></textarea>
<button onclick="parseCSV()">Parse CSV</button>
<div id="tableContainer"></div>

<script>
  function parseCSV() {
    const csvData = document.getElementById('csvData').value;
    const tableContainer = document.getElementById('tableContainer');
    tableContainer.innerHTML = ''; // Clear previous table

    if (!csvData.trim()) return; // No data to parse

    try {
      const rows = csvData.trim().split('\n').map(row => row.trim());
      const table = document.createElement('table');

      // Find max columns
      let maxColumns = 0;
      rows.forEach(row => {
        const columns = row.split(/,(?=(?:[^"]|"[^"]*")*$)/);
        maxColumns = Math.max(maxColumns, columns.length);
      });

      // Create table header
      const thead = document.createElement('thead');
      const theadRow = document.createElement('tr');
      for (let i = 0; i < maxColumns; i++) {
        const th = document.createElement('th');
        th.textContent = `Column ${i + 1}`;
        theadRow.appendChild(th);
      }
      thead.appendChild(theadRow);
      table.appendChild(thead);

      // Create table body
      const tbody = document.createElement('tbody');
      rows.forEach(row => {
        if (!row) return; // Skip empty rows
        const tr = document.createElement('tr');
        const columns = row.split(/,(?=(?:[^"]|"[^"]*")*$)/).map(column => column.replace(/"/g, '').trim());

        for (let i = 0; i < maxColumns; i++) {
          const td = document.createElement('td');
          if (columns[i]) {
            td.textContent = columns[i];
          }
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      });
      table.appendChild(tbody);

      tableContainer.appendChild(table);
    } catch (e) {
      const errorDiv = document.createElement('div');
      errorDiv.className = 'error';
      errorDiv.textContent = 'Error parsing CSV: ' + e.message;
      tableContainer.appendChild(errorDiv);
    }
  }
</script>

</body>
</html>
