function parseCSV() {
  const csvData = document.getElementById('csvData').value;
  if (!csvData) return; // Exit if textarea is empty

  const rows = csvData.trim().split('\n');
  const tableData = [];
  for (let row of rows) {
    tableData.push(parseRow(row));
  }

  // Find max column count
  let maxColumns = 0;
  for (let row of tableData) {
    if (row.length > maxColumns) {
      maxColumns = row.length;
    }
  }

  // Adjust rows to have equal columns by adding empty cells
  for (let i = 0; i < tableData.length; i++) {
    while (tableData[i].length < maxColumns) {
      tableData[i].push('');
    }
  }

  createTable(tableData);
}

function parseRow(row) {
  const escapedRegex = /(?:^|,)([^"]|"[^"]*")*$/; // For handling quoted fields and escaped quotes
  const quoteRegex = /"/g;
  let result = [];
  let currentCell = '';
  let inQuotes = false;
  let prevCharWasEscape = false;

  for (let i = 0; i < row.length; i++) {
    let char = row[i];

    if (char === '"') {
      if (prevCharWasEscape) {
        currentCell += char;
        prevCharWasEscape = false;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      result.push(currentCell);
      currentCell = '';
    } else {
      currentCell += char;
      prevCharWasEscape = (char === '\\');
    }
  }

  result.push(currentCell);

  // Remove quotes and unescape
  return result.map(cell => cell.replace(quoteRegex, '').replace(/\\(.)/g, '$1'));
}

function createTable(tableData) {
  const tableContainer = document.getElementById('tableContainer');
  tableContainer.innerHTML = ''; // Clear previous table

  let table = document.createElement('table');
  for (let i = 0; i < tableData.length; i++) {
    let row = table.insertRow(i);
    for (let j = 0; j < tableData[i].length; j++) {
      let cell = row.insertCell(j);
      cell.textContent = tableData[i][j];
      if (i === 0) {
        cell.style.fontWeight = 'bold'; // Make header bold
      }
    }
  }

  tableContainer.appendChild(table);
}
</script>

