    constructor(theme = 'light') {
        this.theme = theme;
    }

    toggleTheme() {
        this.theme = (this.theme === 'light') ? 'dark' : 'light';
        // Update DOM based on theme
    }
}

// Usage
let themeService = new ThemeService();

// Event listener
document.getElementById('theme-toggle').addEventListener('click', function() {
    themeService.toggleTheme();
    // Update DOM based on themeService.theme
});
```

In this simplified example, `ThemeService` instances can be created and managed more flexibly, allowing for easier testing and less coupling.

