function drawTree(depth) {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.translate(canvas.width / 2, canvas.height);
  ctx.scale(1, -1);

  const stack = [];
  stack.push({ length: 100, depth });

  while (stack.length > 0) {
