        prevCharWasEscape = true;
      } else if (char === '"') {
        inQuotes = !inQuotes;
      } else if (!inQuotes && char === ',') {
        cols.push(currentCol);
        currentCol = '';
      } else {
        currentCol += char;
      }
    }

    cols.push(currentCol); // Push last column

    return cols;
  }
