                    continue;
                }

                if (char === '\\') {
                    escapeNext = true;
                    continue;
                }

                if (char === '"') {
                    inQuote = !inQuote;
                    continue;
                }

                if (!inQuote && char === ',') {
                    cells.push(currentCell);
                    currentCell = '';
                    continue;
                }

                currentCell += char;
            }

            cells.push(currentCell);
            return cells;
        }

        function renderTable(rows) {
            let tableHtml = '<table>';
            for (let i = 0; i < rows.length; i++) {
                tableHtml += '<tr>';
                for (const cell of rows[i]) {
                    tableHtml += `<td>${cell}</td>`;
                }
                tableHtml += '</tr>';
            }
            tableHtml += '</table>';
            return tableHtml;
        }
    </script>
</body>
</html>
