            const pivot = data[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                if (data[j] < pivot) {
                    i++;
                    [data[i], data[j]] = [data[j], data[i]];
                    drawData(data, [i, j]);
                    await new Promise(resolve => setTimeout(resolve, 10));
                    stepCounter.textContent = `Quick sort steps: ${stepCounter.textContent.split(': ')[1] * 1 + 1}`;
                }
            }
            [data[i + 1], data[high]] = [data[high], data[i + 1]];
            drawData(data, [i + 1, high]);
            await new Promise(resolve => setTimeout(resolve, 10));
            stepCounter.textContent = `Quick sort steps: ${stepCounter.textContent.split(': ')[1] * 1 + 1}`;
            return i + 1;
        }

        // Merge sort
        async function mergeSort(data, low, high, stepCounter) {
            if (low < high) {
                const mid = Math.floor((low + high) / 2);
                await mergeSort(data, low, mid, stepCounter);
                await mergeSort(data, mid + 1, high, stepCounter);
                await merge(data, low, mid, high, stepCounter);
            }
        }

        async function merge(data, low, mid, high, stepCounter) {
            const left = data.slice(low, mid + 1);
            const right = data.slice(mid + 1, high + 1);
            let i = 0;
            let j = 0;
            let k = low;
            while (i < left.length && j < right.length) {
                if (left[i] <= right[j]) {
                    data[k] = left[i];
                    i++;
                } else {
                    data[k] = right[j];
                    j++;
                }
                k++;
                drawData(data, [k - 1]);
                await new Promise(resolve => setTimeout(resolve, 10));
                stepCounter.textContent = `Merge sort steps: ${stepCounter.textContent.split(': ')[1] * 1 + 1}`;
            }
            while (i < left.length) {
                data[k] = left[i];
                i++;
                k++;
                drawData(data, [k - 1]);
                await new Promise(resolve => setTimeout(resolve, 10));
                stepCounter.textContent = `Merge sort steps: ${stepCounter.textContent.split(': ')[1] * 1 + 1}`;
            }
            while (j < right.length) {
                data[k] = right[j];
                j++;
                k++;
                drawData(data, [k - 1]);
                await new Promise(resolve => setTimeout(resolve, 10));
                stepCounter.textContent = `Merge sort steps: ${stepCounter.textContent.split(': ')[1] * 1 + 1}`;
            }
        }

        // Start the sorting process
        document.getElementById('start-button').addEventListener('click', async () => {
            initData();
            drawData(data);
            const complexitiesElement = document.getElementById('complexities');
            complexitiesElement.textContent = `
