    function searchSafe() {
        const userInput = document.getElementById("safeInput").value;
        // Simulating a parameterized query by filtering in JavaScript
        // In a real database, you'd use a parameterized query with a library or framework
        const safeQuery = "SELECT * FROM products WHERE name LIKE :name";
        console.log("Safe Query:", safeQuery);

        const results = products.filter(product => product.name.includes(userInput));
        const output = results.map(result => `<p>${result.name} - ${result.description}</p>`).join("");
