                    throw new Error("ThemeState is a singleton!");
                }
                this.theme = "light";
                this.elements = [];
            }

            toggleTheme() {
                this.theme = this.theme === "light" ? "dark" : "light";
                this.elements.forEach(element => element.classList.toggle("light-theme"));
                this.elements.forEach(element => element.classList.toggle("dark-theme"));
                document.body.classList.toggle("light-theme");
                document.body.classList.toggle("dark-theme");
                this.updateThemeStatus();
            }

            registerElement(element) {
                this.elements.push(element);
            }

            updateThemeStatus() {
                document.getElementById("theme-status").innerText = `Current Theme: ${this.theme}`;
            }
        }

        // Usage
        const themeState = ThemeState.getInstance();

        document.getElementById("theme-toggle").addEventListener("click", () => {
            themeState.toggleTheme();
        });

        const elements = document.querySelectorAll(".header, .button, section");
        elements.forEach(element => themeState.registerElement(element));

        themeState.updateThemeStatus();
    </script>

