        function drawBuggySpiral() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.beginPath();
            ctx.strokeStyle = 'red';
            const fibGen = fibonacci();
            let prevX = canvas.width / 2;
            let prevY = canvas.height / 2;
            let angle = 0;
            for (let i = 0; i < 20; i++) {
                const r = fibGen.next().value;
                ctx.moveTo(prevX, prevY);
                ctx.arc(prevX, prevY, r, angle, angle + Math.PI / 2); // Bug: Incorrect angle increment
                prevX += r * Math.cos(angle + Math.PI / 4); // Bug: Incorrect position update
                prevY += r * Math.sin(angle + Math.PI / 4); // Bug: Incorrect position update
                angle += Math.PI / 4; // Bug: Incorrect angle increment
            }
            ctx.stroke();
        }

        // Fixed Fibonacci spiral
        function drawFixedSpiral() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.beginPath();
            ctx.strokeStyle = 'blue';
            const fibGen = fibonacci();
            let prevX = canvas.width / 2;
            let prevY = canvas.height / 2;
            let angle = 0;
            for (let i = 0; i < 20; i++) {
                const r = fibGen.next().value;
                ctx.moveTo(prevX, prevY);
                ctx.arc(prevX, prevY, r, angle, angle + Math.PI / 2);
                prevX += r * Math.cos(angle + Math.PI / 4);
                prevY += r * Math.sin(angle + Math.PI / 4);
                angle += Math.PI / 2; // Fixed angle increment
            }
            ctx.stroke();
        }

        // Draw both spirals
        drawBuggySpiral();
        drawFixedSpiral();
    </script>
</body>
</html>
```

# Explanation of changes:
*   **Bug:** The buggy spiral incorrectly increments the angle by `Math.PI / 4` instead of `Math.PI / 2`, causing the arcs to overlap and not form a spiral.
*   **Fix:** The fixed spiral increments the angle by `Math.PI / 2`, allowing the arcs to form a proper Fibonacci spiral.

